INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('17-referral-ecosystem',2,17,'REFERRAL ECOSYSTEM','He sinh thai gioi thieu khach hang',17,'draft','2026-06-20T14:52:09Z','2026-06-20T14:52:09Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('609aa75a-8d0c-4d4a-a064-81e7a49c1eef','17-referral-ecosystem',NULL,2,'17.1 Bản Đồ Luồng Cốt Lõi Của Hệ Sinh Thái Tăng Trưởng Lan Tỏa','171-ban-o-luong-cot-loi-cua-he-sinh-thai-tang-truong-lan-toa',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('155823bc-7f1d-4e85-8c9c-abcc1b9b2777','609aa75a-8d0c-4d4a-a064-81e7a49c1eef',0,'text','Kiến trúc hệ sinh thái lan tỏa và động cơ tăng trưởng tự thân dựa trên niềm tin thực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('064beac1-e04c-4cd0-bbb8-10458d3476c7','609aa75a-8d0c-4d4a-a064-81e7a49c1eef',1,'text','Trong giai đoạn thị trường nha khoa cạnh tranh khốc liệt, chi phí trên mỗi lượt nhấp chuột (CPC) và chi phí để có một khách hàng tiềm năng (CAC) ngày càng leo thang phi mã trên các nền tảng quảng cáo (Facebook, TikTok, Google). Nếu một phòng khám RHM chỉ biết bám víu vào "bình oxy" quảng cáo trả phí, phòng khám đó đang tự đặt mình vào vùng nguy hiểm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0e26343-a7d8-4c50-b6af-1ec594a133c7','609aa75a-8d0c-4d4a-a064-81e7a49c1eef',2,'text','Trong hệ điều hành **Dental Empire OS**, điểm tiến hóa tối cao của hành trình trải nghiệm bệnh nhân không dừng lại ở một bài review 5 sao. Nó phải được nâng cấp thành một **Referral Ecosystem (Hệ sinh thái giới thiệu khách hàng)** - một bộ máy vận hành có chủ đích nhằm biến lòng biết ơn và sự hài lòng của bệnh nhân cũ thành nguồn nhiên liệu tăng trưởng tự nhiên, miễn phí và vô tận cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2b43342-55d1-4a08-b2b5-eb627a8e38fa','609aa75a-8d0c-4d4a-a064-81e7a49c1eef',3,'text','**Tư duy cốt lõi:** Referral trong nha khoa không phải là hành động "nhờ vả, cầu xin khách hàng làm ơn giới thiệu người quen". Đây là một hệ thống chuyển giao niềm tin được lập trình bài bản, biến mỗi nụ cười thành công thành một đại sứ thương hiệu hoạt động liên tục trên thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c35a582a-7183-4cca-95ee-72ab8266e6e2','609aa75a-8d0c-4d4a-a064-81e7a49c1eef',4,'text','Hệ sinh thái Referral vận hành theo một vòng lặp kín (Loop). Mỗi bệnh nhân đi vào vòng lặp này sẽ tự động sinh ra những bệnh nhân tiếp theo, tạo nên hiệu ứng hòn tuyết lăn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fafd949e-21a0-4fe3-bcf2-3e16563836a2','609aa75a-8d0c-4d4a-a064-81e7a49c1eef',5,'image',NULL,'book/17-referral-ecosystem/766a0313-7d5a-4102-8a91-860e5cdb87db-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('800efce8-cec5-4d89-8e55-346b5cae2424','17-referral-ecosystem',NULL,2,'17.2 Vai Trò Chiến Lược Của Referral Ecosystem Trong Dental Empire OS','172-vai-tro-chien-luoc-cua-referral-ecosystem-trong-dental-empire-os',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('705fb7a3-6276-443c-b158-aba9a78e72c0','800efce8-cec5-4d89-8e55-346b5cae2424',6,'text','Bản chất của các quyết định y khoa liên quan đến sức khỏe, thẩm mỹ và tài chính lớn luôn dựa trên sự an toàn. Bệnh nhân trước khi quyết định can thiệp sâu (Implant, niềng răng, sứ thẩm mỹ) thường sàng lọc thông tin qua 6 bộ lọc khắt khe:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8104799a-c5da-422b-ae2c-1cc31bd9327d','800efce8-cec5-4d89-8e55-346b5cae2424',7,'text','- Lời giới thiệu từ người thân quen đã từng trải nghiệm thực tế.- Hệ thống đánh giá, review chân thực không có dấu hiệu dàn dựng.- Kho hình ảnh, video Case lâm sàng thực tế giống với tình trạng của họ.- Hồ sơ năng lực, uy tín khoa học và phong thái chuyên gia của Bác sĩ.- Cảm giác được chăm sóc chu đáo ngay từ điểm chạm đầu tiên.- Kết quả ăn nhai và thẩm mỹ bền vững theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04866c7b-9b16-4424-99fa-ec1eebf22e3d','800efce8-cec5-4d89-8e55-346b5cae2424',8,'image',NULL,'book/17-referral-ecosystem/4342465a-f98e-4a1d-a364-610e3d7d859d-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('41869f65-47f0-4167-a89e-f29c10a45b8a','800efce8-cec5-4d89-8e55-346b5cae2424',9,'text','Vì vậy, khi phòng khám RHM kích hoạt thành công Hệ sinh thái Referral, doanh nghiệp sẽ đạt được những bước nhảy vọt về mặt chỉ số vận hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11cc3fc4-0abc-4f42-8020-217d3606ad15','800efce8-cec5-4d89-8e55-346b5cae2424',10,'text','- **Cắt bỏ sự phụ thuộc vào Ads:** Giảm tải áp lực ngân sách cho khối Marketing OS. Dòng khách truyền miệng là dòng khách có chi phí thu mua (CAC) tiệm cận bằng 0.- **Tăng chất lượng nguồn Lead:** Khách hàng được giới thiệu là tệp khách có **Intent (Ý định) và độ Nóng cao nhất**. Họ đã được "giáo dục" về niềm tin thông qua người giới thiệu trước khi bước chân vào phòng khám.- **Bẻ gãy rào cản phòng thủ:** Khách đến khám với tâm thế tin tưởng sẵn, triệt tiêu sự hoài nghi ở tầng *Authority Check*, giúp giảm thiểu tối đa thời gian tư vấn.- **Tối ưu tỷ lệ chốt phác đồ (Treatment Acceptance Rate):** Khi niềm tin thị trường tăng cao nhờ hệ thống Social Proof (bằng chứng xã hội) dày đặc, tỷ lệ bệnh nhân gật đầu đồng ý điều trị tại ghế nha sẽ đạt mức tối đa.- **Sản xuất tư liệu truyền thông thực tế:** Từ những ca giới thiệu thành công, phòng khám lại có thêm tư liệu thật để nuôi dưỡng tệp khách hàng đang theo dõi trên các kênh Social.- **Nuôi dưỡng cộng đồng bệnh nhân trung thành:** Biến phòng khám thành một bộ tộc (Tribe) của những người tự hào về nụ cười của mình, sẵn sàng đứng ra bảo vệ và lan tỏa giá trị của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ba77739e-fb88-4b05-8189-742ccf5c8842','17-referral-ecosystem',NULL,2,'17.3 Phương Pháp Kích Hoạt Hệ Sinh Thái Referral Tinh Tế (Tuyệt Đối Không Làm Theo Kiểu Đa Cấp)','173-phuong-phap-kich-hoat-he-sinh-thai-referral-tinh-te-tuyet-oi-khong-lam-theo-',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e615bc26-3e7d-4ed0-8137-05545325d397','ba77739e-fb88-4b05-8189-742ccf5c8842',11,'text','Nhiều phòng khám thất bại khi làm Referral vì sử dụng cơ chế trích phần trăm hoa hồng thô thiển bằng tiền mặt cho người giới thiệu. Trong ngành y khoa, cách làm này phản tác dụng vì nó khiến người giới thiệu mang cảm giác tội lỗi: *"Mình đang bán đứng lòng tin của người thân để lấy tiền"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bae8c21f-a2ec-488a-8862-e7c6e41fdc63','ba77739e-fb88-4b05-8189-742ccf5c8842',12,'text','Hệ sinh thái Referral của Dental Empire OS ứng dụng cơ chế **"Trao tặng đặc quyền" (The Benefactor Experience)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('836e3454-1012-4de2-8b29-a9cca30bf9e8','ba77739e-fb88-4b05-8189-742ccf5c8842',13,'text','- **Vị thế người ban ơn:** Thay vì thưởng tiền, hãy trao cho bệnh nhân cũ những tấm "Thẻ đặc quyền chăm sóc răng miệng VIP" hoặc "Voucher tầm soát chuyên sâu bằng máy CT Cone Beam miễn phí trị giá 1 triệu đồng" để họ mang đi tặng bạn bè. Lúc này, bệnh nhân đi giới thiệu với tâm thế của một người chia sẻ giá trị, một người đi ban tặng cơ hội trải nghiệm dịch vụ đẳng cấp cho người mình yêu thương.- **Cơ chế tri ân song phương (Win - Win Reward):** Khi người mới đến điều trị thành công, phòng khám sẽ tự động gửi một món quà tri ân tinh tế (ví dụ: một gói chăm sóc răng chuyên sâu miễn phí cho cả năm, hoặc một món quà sức khỏe) đến nhà của người giới thiệu cũ, kèm một tấm thiệp viết tay của Bác sĩ trưởng ca. Sự trân trọng này khiến bệnh nhân cũ vô cùng hãnh diện và sẵn sàng giới thiệu thêm nhiều người nữa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7bbaa826-b242-46b7-8909-e7d2b9db664f','17-referral-ecosystem',NULL,2,'17.4 Luồng vận hành chuẩn của hệ sinh thái Referral','174-luong-van-hanh-chuan-cua-he-sinh-thai-referral',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7308a0b2-c5fc-4373-8ea6-c5fdc6d8d6eb','7bbaa826-b242-46b7-8909-e7d2b9db664f',14,'text','Để hệ sinh thái lan tỏa tự nhiên vận hành hiệu quả và liên tục sinh ra dữ liệu khách hàng mới, phòng khám RHM không thể phó mặc cho sự ngẫu nhiên. Trái lại, chúng ta phải lập trình một **Luồng vận hành chuẩn (Standard Operating Flow)** đi qua 3 giai đoạn bản lề: từ việc tạo dựng cốt lõi sự hài lòng, chọn thời điểm kích hoạt khôn khéo, cho đến quy trình tiếp nhận lead được giới thiệu bằng kịch bản neo giữ niềm tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('186b66c5-8382-4026-b84e-9c43c16fc92e','7bbaa826-b242-46b7-8909-e7d2b9db664f',15,'image',NULL,'book/17-referral-ecosystem/3f72512b-ba3d-4f2f-b375-fb644d2bc054-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('03860a3b-75cc-4548-85ea-6c4920df3254','17-referral-ecosystem',NULL,2,'17.5 Điểm Khởi Đầu','175-iem-khoi-au',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08f2b509-fcae-4cb5-a785-ce5937111271','03860a3b-75cc-4548-85ea-6c4920df3254',16,'text','**Bệnh Nhân Hài Lòng - Khi Trải Nghiệm Thay Thế Mọi Chiêu Trò Ưu Đãi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ad8381a-7d6d-499a-84de-8ce375b3047b','03860a3b-75cc-4548-85ea-6c4920df3254',17,'text','Trong hệ điều hành **Dental Empire OS**, tôi luôn quán triệt một nguyên lý bất biến: Điểm khởi đầu của Referral không phải là những chương trình giảm giá sâu, cũng không phải là những chiếc voucher bóng bẩy. **Nhiên liệu duy nhất kích hoạt cỗ máy lan tỏa chính là một trải nghiệm lâm sàng và dịch vụ "wow peak". **',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8fa752b-ceac-4458-868e-222cc39e3dd3','03860a3b-75cc-4548-85ea-6c4920df3254',18,'text','Bệnh nhân mang danh dự và uy tín cá nhân của họ ra để đánh cược khi giới thiệu một phòng khám cho người thân, bạn bè. Họ sẽ tuyệt đối im lặng nếu hệ thống của bạn vận hành hời hợt. Bệnh nhân chỉ chủ động chia sẻ với người thân khi và chỉ khi họ được thỏa mãn trọn vẹn 7 điều kiện tâm lý cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b1e892f-7bb1-4e9a-a77d-2cceec672088','03860a3b-75cc-4548-85ea-6c4920df3254',19,'text','- **Được chăm sóc thấu cảm:** Cảm nhận được sự trân quý từ tất cả các bộ phận trong suốt hành trình điều trị.- **Được Bác sĩ minh bạch hóa thông tin:** Hiểu rõ tường tận phác đồ y khoa, nguyên nhân bệnh lý thay vì những lời phán xét mơ hồ.- **Điều trị đạt kết quả thực tế:** Chức năng ăn nhai được khôi phục, tính thẩm mỹ được khẳng định bằng mắt thấy tai nghe.- **Không bị ép bán (Zero-Exploitation):** Hoàn toàn tự nguyện điều trị, không có cảm giác bị chèo kéo, "vẽ bệnh" để ép doanh số.- **Không bị bỏ rơi hậu phẫu:** Phòng khám chủ động bám sát, hỏi thăm từng cơn đau, cơn sưng khi họ đã về nhà.- **Tin tưởng tuyệt đối vào thương hiệu:** Công nhận năng lực chuyên môn và đạo đức y đức của phòng khám.- **Tự hào khi chia sẻ:** Cảm thấy việc giới thiệu nơi này sẽ giúp nâng cao giá trị bản thân và thực sự giúp ích cho người xung quanh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4c100ecd-e4d6-408b-a827-9e298b52f785','17-referral-ecosystem',NULL,2,'','',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2271bc4f-2c9a-4cf8-b9a7-9469bad6a5df','4c100ecd-e4d6-408b-a827-9e298b52f785',20,'image',NULL,'book/17-referral-ecosystem/72cb72c2-eb66-4f7b-9e58-8968ca4728aa-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f13e2a03-e421-4161-be77-ae7812128800','17-referral-ecosystem',NULL,2,'17.6 Nghệ Thuật Kích Hoạt Giới Thiệu Khách','176-nghe-thuat-kich-hoat-gioi-thieu-khach',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82e7cfe6-3061-4ed9-9ce9-3bc30852f9b1','f13e2a03-e421-4161-be77-ae7812128800',21,'text','**Chọn Đúng "Thời Điểm Vàng" Để Khơi Gợi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d53035ee-01b9-4d87-a539-d9ff73c88ff4','f13e2a03-e421-4161-be77-ae7812128800',22,'text','Sự hài lòng của khách hàng giống như một dòng chảy cảm xúc, nếu phòng khám im lặng quá lâu, dòng chảy đó sẽ nguội lạnh. Sau khi bệnh nhân đạt đến đỉnh cao của sự thỏa mãn (Wow Peak), đội ngũ tư vấn và CSKH phải chủ động mở lời để khơi gợi nhu cầu lan tỏa, tuyệt đối không chờ đợi khách hàng tự nhớ đến mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b44c18fe-6321-4590-897a-d8b7c3050184','f13e2a03-e421-4161-be77-ae7812128800',23,'text','**Các thời điểm hoàn hảo để kích hoạt lời mời giới thiệu:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3b5f7b3-6c07-4a63-ab90-7e608b5463db','f13e2a03-e421-4161-be77-ae7812128800',24,'text','- **Ngay khi tháo niềng / Gắn răng sứ / Hoàn thiện Implant:** Khi khách hàng soi gương và vỡ òa hạnh phúc trước nụ cười mới đổi thay ngoạn mục.- **Tại quầy lễ tân khi khách chủ động khen ngợi:** Khách nói: *"Bác sĩ Vinh làm nhẹ tay quá em, về nhà không sưng chút nào"*.- **Buổi tái khám định kỳ sau 6 tháng:** Khi kết quả điều trị đã được thời gian bảo chứng về độ bền và tính ổn định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c58bb08-41d6-4ff8-8385-1ad8948215b7','f13e2a03-e421-4161-be77-ae7812128800',25,'text','**Kịch bản khơi gợi tinh tế tại ghế nha (Dành cho Bác sĩ / Trợ thủ):***"Nhìn thấy anh/chị ****[Tên_Bệnh_Nhân]**** hôm nay ăn nhai thoải mái và tự tin cười rạng rỡ thế này, cả ê-kíp bên em đều thực sự hạnh phúc. Công việc bận rộn hằng ngày đôi khi khiến nhiều người quên đi việc chăm sóc răng, dẫn đến lúc phát hiện ra thì bệnh lý đã nặng rồi. Nếu trong gia đình hoặc bạn bè đồng nghiệp của anh/chị có ai cũng đang gặp tình trạng răng nhạy cảm, ê buốt hoặc mất răng tương tự như mình trước đây, anh/chị cứ nhắn họ qua đây nhé. Phòng khám bên em luôn sẵn lòng ưu tiên đặt lịch để kiểm tra, chụp phim và tư vấn phác đồ kỹ lưỡng nhất cho người nhà của mình ạ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c4418bec-1abc-4fd8-ac99-c536cc4e9b98','17-referral-ecosystem',NULL,2,'17.7 Quy Trình Tiếp Nhận Và Chuyển Đổi Khách Hàng Được Giới Thiệu (Onboarding Workflow)','177-quy-trinh-tiep-nhan-va-chuyen-oi-khach-hang-uoc-gioi-thieu-onboarding-workfl',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca9978fe-7fb4-4af0-85b8-7ff632060f75','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',26,'text','Tệp lead đổ về từ nguồn giới thiệu (Referral Leads) sở hữu một đặc tính vô giá: **Họ đã có sẵn 80% niềm tin vào bạn.** Họ tự động bỏ qua tầng hoài nghi ở lớp *Trust* và *Authority Check* vì đã được "giáo dục" bởi sự lột xác của người giới thiệu. Do đó, quy trình tiếp nhận phải cực kỳ tinh tế để không làm gãy đổ sợi dây liên kết tin cậy này:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('217dd563-0e5c-4b50-97f7-054300ea95e8','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',27,'image',NULL,'book/17-referral-ecosystem/8386fe8a-2d14-4df2-b078-17d049a4ef57-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e024ff77-b1a6-4ea6-9268-2e1f66b43b79','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',28,'text','Khi bộ phận CSKH bốc máy gọi điện tiếp cận tệp khách hàng đặc biệt này, chìa khóa chiến thắng nằm ở việc **mở đầu cuộc hội thoại bằng niềm tin của người đi trước**. Tuyệt đối không dùng kịch bản chào hàng lạnh lùng (Cold Call).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65710151-f6cf-4403-a9e8-cd50033fa260','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',29,'text','***Kịch bản Telesale chuẩn mực đón tiếp Lead Giới thiệu:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92519fc5-6804-4d93-b324-1f6ba954bed7','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',30,'text','"Em chào anh/chị **[Tên_Khách_Mới]**, em là **[Tên_Nhân_Vien]** gọi điện từ Nha khoa **[Tên_Phòng_Khám]** ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9160b0ca-6879-4d06-b681-fc4a9a39ef74','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',31,'text','Anh/chị ơi, hôm nay phòng khám bên em có nhận được thông tin từ anh/chị **[Tên_Người_Giới_Thiệu]** — vốn là một bệnh nhân rất thân thiết vừa hoàn thành điều trị tại bên em. Anh/chị **[Tên_Người_Giới_Thiệu]** có chia sẻ rằng hiện tại mình cũng đang gặp tình trạng **[vấn đề răng miệng của khách mới, ví dụ: bị mất răng hàm/đang muốn tìm hiểu niềng răng]** và có dặn em phải chủ động liên hệ để hỗ trợ mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c638961e-a0e4-45af-85a0-bf2c30cac86d','c4418bec-1abc-4fd8-ac99-c536cc4e9b98',32,'text','Vì anh/chị là người nhà do đích thân anh/chị **[Tên_Người_Giới_Thiệu]** gửi gắm, Bác sĩ trưởng ca bên em đã xếp riêng một khung giờ đặc quyền vào **[Ngày/Giờ]** tuần này để trực tiếp chụp phim CT Cone Beam và tầm soát cấu trúc răng toàn diện cho mình. Em xin phép giúp anh/chị khóa khung giờ này để qua gặp Bác sĩ kiểm tra kỹ lưỡng nhất cho mình nhé ạ?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('50035a7e-5ee8-484e-9bf0-ea344c1e071c','17-referral-ecosystem',NULL,2,'17.8 Testimonial System','178-testimonial-system',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e506a7c-d026-459e-820c-480e36860ea9','50035a7e-5ee8-484e-9bf0-ea344c1e071c',33,'text','**Quy trình số hóa câu chuyện lột xác và khai thác "vũ khí" thuyết phục tối thượng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bdd0da9f-1ce1-448f-aec3-bbd5aef98e39','50035a7e-5ee8-484e-9bf0-ea344c1e071c',34,'text','Trong hệ điều hành **Dental Empire OS**, tôi định nghĩa Testimonial (Lời chứng thực) không đơn thuần là vài câu khen ngợi vô thưởng vô phạt của bệnh nhân. Testimonial là **Tư liệu cảm xúc có cấu trúc**, phản ánh chân thực toàn bộ hành trình từ đau đớn, tự ti đến hạnh phúc, tự tin của một con người.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3dfb3433-4229-4e8a-b326-4362e6d348d9','50035a7e-5ee8-484e-9bf0-ea344c1e071c',35,'text','Khách hàng thế hệ mới ngày càng hoài nghi quảng cáo. Họ không còn tin vào những lời tự ca ngợi của phòng khám. Thứ duy nhất có thể bẻ gãy lớp phòng vệ lý trí của họ là sự đồng cảm khi nhìn thấy câu chuyện của một người khác có cùng nỗi sợ, cùng tình trạng răng miệng giống hệt họ đã được chữa khỏi thành công tại phòng khám của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff0fbf64-75d4-4446-825b-6a917991e2b5','50035a7e-5ee8-484e-9bf0-ea344c1e071c',36,'text','Xây dựng hệ thống **Testimonial System** bài bản là cách bạn liên tục "sản xuất" ra những vũ khí tiếp thị có sức công phá mạnh nhất, phục vụ trực tiếp cho đội ngũ Sales bẻ gãy mọi lời từ chối ở tầng *Conversion*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('50bca200-6f08-45b7-8c91-f36d3a984d2c','17-referral-ecosystem','50035a7e-5ee8-484e-9bf0-ea344c1e071c',3,'Các dạng Testimonial cốt lõi trong nha khoa thực chiến','cac-dang-testimonial-cot-loi-trong-nha-khoa-thuc-chien',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7991726-89bb-4bf5-ae08-d1bdb0cbc9a3','50bca200-6f08-45b7-8c91-f36d3a984d2c',37,'text','Để bao phủ mọi điểm chạm và phù hợp với thói quen tiêu thụ nội dung đa dạng của các tệp bệnh nhân, phòng khám RHM cần đa dạng hóa kho tài sản chứng thực thành 4 định dạng bản lề:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29ae6f48-5121-4da1-abfc-721db815a11a','50bca200-6f08-45b7-8c91-f36d3a984d2c',38,'text','- **Dạng 1: Text & Image (Bài viết trải nghiệm kèm hình ảnh lâm sàng):** Đoạn chia sẻ ngắn, chân thực của khách hàng kết hợp với ảnh nụ cười rạng rỡ hoặc ảnh Bác sĩ trao quà tri ân. Đây là định dạng có chi phí sản xuất thấp nhất, dễ đọc lướt, cực kỳ phù hợp để phân phối chéo lên Fanpage Facebook, Zalo OA hoặc trang chủ Website.- **Dạng 2: Short Video Feedback (Video cảm nhận ngắn từ 1 - 3 phút):** Đoạn phim ngắn bắt trọn biểu cảm gương mặt, tông giọng hồ hởi và nụ cười tự nhiên của bệnh nhân ngay tại ghế nha hoặc quầy lễ tân sau khi hoàn tất điều trị. Đây là "mồi nhử niềm tin" cực mạnh có tỷ lệ phân phối tự nhiên rất cao trên các nền tảng video ngắn như TikTok, Facebook Reels và YouTube Shorts.- **Dạng 3: Third-Party Platform Reviews (Đánh giá trên nền tảng thứ ba):** Các bài nhận xét, chấm sao trực tiếp từ tài khoản cá nhân của bệnh nhân hiển thị công khai trên Google Maps, hội nhóm cộng đồng. Định dạng này mang tính khách quan tuyệt đối, trực tiếp đẩy mạnh điểm số hiển thị ở tầng *Search Layer* và củng cố uy tín cho phòng khám.- **Dạng 4: Deep Case Study / Documentary Video (Phóng sự tài liệu chuyên sâu):** Thước phim chuyên nghiệp kéo dài 3 - 5 phút, đào sâu vào cuộc đời của bệnh nhân trước và sau khi làm răng (Dành riêng cho các ca lớn như Implant toàn hàm All-on-X, Niềng răng phức tạp thay đổi cấu trúc mặt). Video được thiết kế theo cấu trúc Storytelling (Kể chuyện): Nỗi đau, sự bế tắc của cuộc sống cũ \\rightarrow Hành trình tìm kiếm cứu cánh \\rightarrow Khoảnh khắc lột xác thay đổi số phận. Đây là vũ khí tối thượng để chốt những ca điều trị giá trị cao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3e9d6827-cc4e-491b-8454-c5ad1e86fb39','17-referral-ecosystem','50035a7e-5ee8-484e-9bf0-ea344c1e071c',3,'Quy trình sản xuất và phân phối Testimonial chuẩn','quy-trinh-san-xuat-va-phan-phoi-testimonial-chuan',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7a7c0c1-35ae-42ee-beed-e33986bf2521','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',39,'text','Việc thu thập tư liệu chứng thực không được làm tùy hứng mà phải vận hành như một dây chuyền công nghiệp đóng gói cảm xúc, tuân thủ nghiêm ngặt theo các bước dưới đây để bảo bối này đạt chất lượng cao nhất:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af84583b-ebcf-494c-bdc5-a5cfc7c78674','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',40,'text','- **Hoàn tất điều trị lâm sàng: **Mốc Wow Peak.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('105cdd69-3921-422c-a0c8-22f427b09768','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',41,'text','Bệnh nhân bước xuống khỏi ghế nha sau khi đạt kết quả điều trị xuất sắc (gắn răng sứ hoàn thiện, tháo niềng). Chỉ số hạnh phúc và lòng biết ơn của họ đang ở mức cao nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5acb6b47-bc27-494f-9e6c-3e5542ae5531','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',42,'text','- **Khảo sát cảm nhận sâu: **Patient Care sàng lọc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f142f7a-febe-4240-8cb4-0cf2af8b8b56','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',43,'text','Bộ phận Chăm sóc bệnh nhân trò chuyện, hỏi thăm một cách tự nhiên để xác định chắc chắn khách hàng đang có trạng thái hài lòng vượt mong đợi (Tag: High_Satisfaction).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e0f4c17-0ef3-45fd-830d-47956a98ddab','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',44,'text','- **Xin phép khai thác tư liệu: **Tôn trọng quyền riêng tư.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d6b259b-ced9-4763-b7ac-4da59e168357','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',45,'text','Nhân viên tinh tế ngỏ lời xin phép được ghi lại những chia sẻ quý báu của khách hàng để làm tư liệu lưu niệm và giúp đỡ những bệnh nhân có nỗi sợ tương tự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a31e9b81-dcb8-49eb-91b2-ba7c45b01edc','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',46,'text','- **Phỏng vấn theo khung câu hỏi vàng: **Chọn hình thức sản xuất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('024a340e-3ffb-4423-a882-c9204b336383','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',47,'text','Tùy vào mức độ cởi mở của khách, nhân viên lựa chọn hình thức phù hợp: Hướng dẫn khách quét mã QR viết bài lên Google Maps, chụp ảnh tư liệu hoặc bật máy quay phỏng vấn trực tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6545b53b-a06e-4b81-b326-d121f3659ea2','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',48,'text','- **Đóng gói và lưu trữ vào Trust Assets: **Hệ thống hóa dữ liệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3592f9b-6145-4de2-a809-fa9ed467e6cf','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',49,'text','Đội ngũ Marketing tiến hành cắt dựng video, biên tập bài viết, chuẩn hóa hình ảnh Before/After và gắn tag lưu trữ vào kho tài nguyên chung để Sales dễ dàng truy xuất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b2a1e14-7639-4365-a6fc-60305ab51023','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',50,'text','- **Đa kênh phân phối: **Kích hoạt tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('754a2399-c2c9-4654-bb8c-fb459d39eec2','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',51,'text','Đẩy nội dung lên hệ sinh thái số (Facebook, TikTok, Website, Google Maps) để nuôi dưỡng các tệp lead lạnh và làm chất xúc tác cho dòng khách hàng mới chủ động tìm đến.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1aa7c2be-1612-4c64-ab7f-66e49266f947','3e9d6827-cc4e-491b-8454-c5ad1e86fb39',52,'image',NULL,'book/17-referral-ecosystem/b6aed619-a28c-4b89-813e-b74871362581-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f98cff1f-b589-486a-93f9-9fa44914823a','17-referral-ecosystem','50035a7e-5ee8-484e-9bf0-ea344c1e071c',3,'Bộ khung câu hỏi vàng để khai thác tâm lý bệnh nhân','bo-khung-cau-hoi-vang-e-khai-thac-tam-ly-benh-nhan',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e36c38fb-be49-4818-b799-edc1728f22e7','f98cff1f-b589-486a-93f9-9fa44914823a',53,'text','Một lỗi rất nặng của nhân viên khi lấy Testimonial là hỏi những câu hỏi mở chung chung khiến khách chỉ biết trả lời: *"Phòng khám tốt, Bác sĩ nhiệt tình"*. Những lời chứng thực này hoàn toàn vô hại nhưng cũng vô giá trị về mặt chuyển đổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c04c536c-34c9-4593-99c8-5ea60d2f92fd','f98cff1f-b589-486a-93f9-9fa44914823a',54,'text','Để Testimonial trở thành một câu chuyện có sức nặng chạm thẳng vào trái tim người đọc, nhân viên CSKH hoặc Bác sĩ cần dẫn dắt bằng **Bộ 5 câu hỏi tâm lý chiến lược** sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82596918-833c-4635-99d0-e643b877c194','f98cff1f-b589-486a-93f9-9fa44914823a',55,'text','**Câu hỏi 1: **"Trước khi quyết định điều trị tại đây, điều gì khiến anh/chị lo lắng, sợ hãi hoặc đắn đo nhất?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c29c2038-b930-4ea6-92ab-9d520919db0d','f98cff1f-b589-486a-93f9-9fa44914823a',56,'text','- *Mục đích:* Kích hoạt việc gọi tên nỗi đau (Pain point) và nỗi sợ phổ biến của thị trường (Sợ đau, sợ tốn tiền, sợ biến chứng hỏng răng). Khi người lạ đọc đến ý này, họ sẽ thấy hình bóng của mình trong đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50670d82-ca3e-40b6-ac1b-6f97d3eca9d6','f98cff1f-b589-486a-93f9-9fa44914823a',57,'text','**Câu hỏi 2:** "Giữa rất nhiều nha khoa ngoài kia, cơ duyên hoặc lý do đặc biệt nào đã khiến anh/chị tin tưởng lựa chọn phòng khám bên em?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aba0a86c-cca9-46c4-a624-a48956287475','f98cff1f-b589-486a-93f9-9fa44914823a',58,'text','- *Mục đích:* Để chính khách hàng nói ra điểm độc nhất vô nhị (USP) của bạn (Ví dụ: Vì xem video thấy Bác sĩ giải thích rất thật, vì được bạn thân giới thiệu, vì ấn tượng với phòng vô trùng trung tâm). Lời khen từ miệng khách hàng có giá trị gấp vạn lần lời quảng cáo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d224bc82-3981-47fc-923c-3b4edefc2fd4','f98cff1f-b589-486a-93f9-9fa44914823a',59,'text','**Câu hỏi 3:** "Trong suốt quá trình nằm trên ghế răng để Bác sĩ thực hiện, cảm nhận thực tế của anh/chị như thế nào? Có đáng sợ hay đau nhức như mình từng lo nghĩ không?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9eb78ac-0870-4c0d-9584-4024cb3b68dc','f98cff1f-b589-486a-93f9-9fa44914823a',60,'text','- *Mục đích:* Triệt tiêu "bóng ma nỗi sợ đau" cho những người xem sau. Câu trả lời thực tế kiểu *"Bác sĩ tiêm tê êm lắm, lúc làm tôi còn ngủ quên mất"* chính là liều thuốc an thần mạnh nhất cho các lead đang do dự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49413ab9-aaea-4ae5-a61a-cceca9c934a3','f98cff1f-b589-486a-93f9-9fa44914823a',61,'text','**Câu hỏi 4: **"Anh/chị cảm thấy thế nào về nụ cười, chức năng ăn nhai và diện mạo hiện tại của mình sau khi hoàn thành điều trị?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5574800d-a3fa-4b27-b798-52fe490278b3','f98cff1f-b589-486a-93f9-9fa44914823a',62,'text','- *Mục đích:* Làm nổi bật kết quả lột xác ngoạn mục (The Transformation). Hãy để khách hàng tự hào khoe về việc họ đã có thể ăn uống ngon miệng ra sao, tự tin giao tiếp và thăng tiến trong công việc thế nào từ khi có hàm răng mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bba9b6e9-574f-4e96-a4f4-0ec4a7002020','f98cff1f-b589-486a-93f9-9fa44914823a',63,'text','**Câu hỏi 5:** "Nếu có một lời khuyên chân thành dành cho những người cũng đang bị tình trạng răng giống mình nhưng vẫn đang sợ hãi, chần chừ chưa dám đi làm, anh/chị sẽ nói với họ điều gì?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('99ac1321-4a08-4b66-85b1-74853ba9a2df','f98cff1f-b589-486a-93f9-9fa44914823a',64,'text','- *Mục đích:* Kích hoạt lời kêu gọi hành động tự nhiên (Call to Action). Lúc này, bệnh nhân cũ đang đóng vai một người đi trước đầy kinh nghiệm, đưa ra lời khuyên kéo khách mới đến với phòng khám của bạn bằng sự tử tế và tình yêu thương.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6db40f70-3ad2-48a7-8657-6cfaca860abd','f98cff1f-b589-486a-93f9-9fa44914823a',65,'text','Kết luận:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c8133a60-5c4a-4c29-ba04-bad13175c219','f98cff1f-b589-486a-93f9-9fa44914823a',66,'image',NULL,'book/17-referral-ecosystem/cc8665cd-4350-4d2c-a7eb-b2b6bf3c21f3-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f3b19f9e-f90b-4340-bec8-753b32141fd1','17-referral-ecosystem',NULL,2,'17.9 Clinic Case Assets','179-clinic-case-assets',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('035b0511-d941-4fba-91e5-ab0f3f44c56a','f3b19f9e-f90b-4340-bec8-753b32141fd1',67,'text','**Chiến lược biến mỗi ca lâm sàng thành tài sản truyền thông và bảo chứng chuyên môn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5e4222e1-fa1f-402a-9030-7ca1c0fa894f','f3b19f9e-f90b-4340-bec8-753b32141fd1',68,'text','Trong hệ điều hành **Dental Empire OS**, tôi luôn nhắc nhở các chủ phòng khám một tư duy: Bệnh nhân mới được dịch chuyển từ nguồn giới thiệu (Referral Lead) không đơn thuần là một chỉ số doanh thu đổ về túi. Mỗi một bệnh nhân bước vào điều trị thành công chính là một tác phẩm nghệ thuật, một **Ca lâm sàng mới (Clinical Case Asset)** đóng vai trò làm nền móng vững chắc cho toàn bộ hệ thống vĩ mô của phòng khám RHM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45bdb981-2c10-4bd3-8a39-a6612f7564bc','17-referral-ecosystem','f3b19f9e-f90b-4340-bec8-753b32141fd1',3,'Vai trò của Clinic Case Assests','vai-tro-cua-clinic-case-assests',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21a16cc8-35bb-49e2-b33e-df45182cc075','45bdb981-2c10-4bd3-8a39-a6612f7564bc',69,'text','Trong y khoa nói chung và nha khoa nói riêng, "Case thật" (Bằng chứng người thật việc thật) là thứ ngôn ngữ quyền lực nhất. Khách hàng có thể nghi ngờ lời một chuyên viên tư vấn, nhưng họ không thể phủ nhận hình ảnh chụp X-quang sắc nét hay sự thay đổi ngoạn mục của một form răng sứ, một cung niềng hoàn hảo. Việc liên tục thu hoạch và đóng gói các ca lâm sàng mới sẽ trực tiếp kiến tạo nên 6 tầng giá trị cốt lõi cho phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('baba1080-d1ec-44b8-a7f7-3c2c9150a8d0','45bdb981-2c10-4bd3-8a39-a6612f7564bc',70,'text','- **Đào tạo và chuẩn hóa đội ngũ (Internal Calibration):** Biến các ca thực tế thành học liệu nội bộ, giúp các bác sĩ trẻ và phụ tá liên tục soi chiếu, học hỏi phác đồ điều trị của các bác sĩ trưởng ca, nâng cao năng lực đồng đều cho toàn bộ Clinic System.- **Nhiên liệu sản xuất nội dung sạch:** Cung cấp nguồn tư liệu "real" 100% cho khối Marketing OS. Bạn không còn phải đi mua hay cóp nhặt hình ảnh stock sáo rỗng trên mạng, toàn bộ nội dung truyền thông đều mang hơi thở thực tế của chính phòng khám.- **Bảo chứng uy tín chuyên môn tuyệt đối (E-E-A-T | Experience - Expertise - Authoritativeness - Trustworthiness):** Khẳng định năng lực xử lý các ca từ trung bình đến cực khó (như tiêu xương hàm nặng, lệch lạc khớp cắn nghiêm trọng) trước giới chuyên môn và các bộ máy tìm kiếm thông minh. - **Đập tan mọi sự phòng thủ của khách hàng mới:** Trở thành thứ vũ khí tối thượng giúp đội ngũ Sales điều hướng tâm lý. Khi khách mới lo sợ: *"Trường hợp của tôi phức tạp thế này có làm được không?"*, Sales chỉ cần mở kho dữ liệu ca tương tự để chứng minh.- **Xây dựng tài sản thương hiệu độc bản:** Kho dữ liệu Case Study càng dày theo năm tháng, giá trị vô hình của phòng khám càng tăng vọt. Đây là tấm khiên vững chắc giúp bạn không bị cuốn vào cuộc chiến cạnh tranh phá giá trên thị trường.- **Kích hoạt vòng lặp Referral tiếp theo:** Khi ca lâm sàng của bệnh nhân được giới thiệu hoàn thành xuất sắc, họ sẽ lại mang chính câu chuyện lột xác của mình đi lan tỏa cho tệp quan hệ xung quanh họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4c9d7eda-2140-4384-9ad7-7058afcdf67f','17-referral-ecosystem','f3b19f9e-f90b-4340-bec8-753b32141fd1',3,'Quy trình tiêu chuẩn đóng gói các ca lâm sàng mới (Clinic Case Pipeline)','quy-trinh-tieu-chuan-ong-goi-cac-ca-lam-sang-moi-clinic-case-pipeline',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c4da62f-0b07-4dae-a064-e35ce301c863','4c9d7eda-2140-4384-9ad7-7058afcdf67f',71,'text','Để một ca điều trị thực tế không bị trôi đi một cách lãng phí và được chuyển hóa trọn vẹn thành tài sản truyền thông, toàn bộ ê-kíp gồm Bác sĩ điều trị, Trợ thủ và Chuyên viên Patient Care bắt buộc phải tuân thủ nghiêm ngặt quy trình 8 bước dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b3f4238-1ea8-4f1c-b36c-9565a4db16fc','4c9d7eda-2140-4384-9ad7-7058afcdf67f',72,'text','- **Tiếp nhận và định danh: **Onboarding Stage.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2a09e80-f108-4c94-a816-a2572c8bf027','4c9d7eda-2140-4384-9ad7-7058afcdf67f',73,'text','Bệnh nhân từ nguồn giới thiệu bước vào phòng khám. Hệ thống CRM lập tức ghi nhận, gắn tag phân loại tình trạng bệnh lý ban đầu và chỉ định bác sĩ phụ trách hồ sơ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b050820-2721-4a10-a5bd-ed05b466980a','4c9d7eda-2140-4384-9ad7-7058afcdf67f',74,'text','- **Tư liệu hóa trạng thái ban đầu: **Baseline Data - Before.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1711bfec-2313-4c9b-92ce-23153eb2b81b','4c9d7eda-2140-4384-9ad7-7058afcdf67f',75,'text','Trợ thủ tiến hành chụp ảnh chân dung, ảnh cận cảnh các góc trong miệng theo đúng bộ kit tiêu chuẩn studio nha khoa, kết hợp lưu trữ file phim chụp X-quang CT Cone Beam trước khi can thiệp y khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('683e15ac-83b0-44b4-bd60-b2bb737bfae6','4c9d7eda-2140-4384-9ad7-7058afcdf67f',76,'text','- **Lập phác đồ và số hóa kế hoạch: **Treatment Mapping.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c258d35d-79b8-481e-8e0e-369ea17e25ee','4c9d7eda-2140-4384-9ad7-7058afcdf67f',77,'text','Bác sĩ trưởng ca phân tích dữ liệu, thiết lập kế hoạch điều trị chi tiết theo từng giai đoạn. Toàn bộ phác đồ và hình ảnh dự phóng kết quả được số hóa, lưu trữ cẩn thận trên hệ thống dữ liệu chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('41fa1abd-7482-4cd3-908d-35d9a31cf4f3','4c9d7eda-2140-4384-9ad7-7058afcdf67f',78,'text','- **Ghi nhận tiến trình can thiệp: **In-Progress Monitoring.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81939f41-b73e-4436-90e2-d3ff5d456cc6','4c9d7eda-2140-4384-9ad7-7058afcdf67f',79,'text','Tại các mốc thời gian quan trọng (siết răng định kỳ, cắm trụ implant, thử sườn sứ), trợ thủ có nhiệm vụ ghi lại các hình ảnh, thước phim ngắn về thao tác lâm sàng của bác sĩ để làm bằng chứng quy trình chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('126a0ccc-2206-4752-99ea-dc8eab137dbf','4c9d7eda-2140-4384-9ad7-7058afcdf67f',80,'text','- **Đóng gói kết quả sau điều trị: **Outcome Data - After.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9917109f-801f-4d1b-94c3-c512f0b26dbf','4c9d7eda-2140-4384-9ad7-7058afcdf67f',81,'text','Ca điều trị hoàn tất hoàn hảo. Tiến hành chụp lại toàn bộ bộ ảnh chân dung, nụ cười rạng rỡ và chức năng ăn nhai mới của bệnh nhân dưới cùng một điều kiện ánh sáng và góc chụp như Bước 2.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6afe1edc-4eda-42e8-b7d1-d672427a345c','4c9d7eda-2140-4384-9ad7-7058afcdf67f',82,'text','- **Kiểm duyệt bản quyền y khoa: **Legal Consent.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2a9ddb6-482a-4cd2-9863-3c59ebcfb292','4c9d7eda-2140-4384-9ad7-7058afcdf67f',83,'text','Bộ phận Patient Care gặp gỡ, trao đổi tinh tế và xin chữ ký của bệnh nhân vào "Văn bản chấp thuận sử dụng hình ảnh ca lâm sàng" nhằm bảo mật thông tin cá nhân và hợp pháp hóa tư liệu truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78f5a452-f4d4-4a9d-8a32-211e3627201c','4c9d7eda-2140-4384-9ad7-7058afcdf67f',84,'text','- **Biên tập câu chuyện ca lâm sàng: **Medical Storytelling.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5beda37d-2467-4338-9990-67daf6eaaf78','4c9d7eda-2140-4384-9ad7-7058afcdf67f',85,'text','Đội ngũ Marketing phối hợp với Bác sĩ để dịch thuật dữ liệu thô thành một câu chuyện truyền cảm hứng: Nỗi đau, hành trình vượt qua nỗi sợ, giải pháp y khoa đột phá và nụ cười hạnh phúc hiện tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62917139-3fa0-44f6-b7fd-6364430a7419','4c9d7eda-2140-4384-9ad7-7058afcdf67f',86,'text','- **Kích hoạt phân phối đa kênh: **Multi-Channel Omnipresence.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7496424-be58-4573-a3dc-63dd5162034e','4c9d7eda-2140-4384-9ad7-7058afcdf67f',87,'text','Đẩy ca lâm sàng hoàn thiện vào kho Trust Assets phục vụ nội bộ, đồng thời phân phối lên Website chuẩn SEO, Google Maps để đón đầu tầng Search Layer và phủ sóng các kênh Social Media.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e5d83971-a0b8-4225-8f92-9a24ce663e44','17-referral-ecosystem','f3b19f9e-f90b-4340-bec8-753b32141fd1',3,'Cấu trúc một Clinic Case chuẩn','cau-truc-mot-clinic-case-chuan',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('677b75d3-f516-437d-ade1-6c432b7ee304','e5d83971-a0b8-4225-8f92-9a24ce663e44',88,'text','**Công thức phát triển nội dung song hành giữa y khoa và tiếp thị**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fead5761-54bf-4fd0-93ab-a7db87b5658e','e5d83971-a0b8-4225-8f92-9a24ce663e44',89,'text','Trong hệ điều hành **Dental Empire OS**, một Ca lâm sàng chuẩn (Clinic Case Asset) không bao giờ được phép làm theo kiểu sơ sài là chỉ đăng hai bức ảnh "Trước - Sau" lên mạng kèm một dòng mô tả ngắn ngủi. Cách làm đó đã quá lỗi thời và không đủ sức nặng để vượt qua bộ lọc hoài nghi của khách hàng thế hệ mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d2c9b86-516f-476a-ab0b-262cab655bc4','e5d83971-a0b8-4225-8f92-9a24ce663e44',90,'text','Một Case Asset chuẩn mực phải là một tài liệu có cấu trúc logic chặt chẽ. Nó phải dung hợp được hai yếu tố: **Tính chính xác, minh bạch về mặt Y khoa** (để bảo chứng chuyên môn cho *Clinic System*) và **Sức chạm sâu sắc về mặt Cảm xúc** (để làm đòn bẩy chuyển hóa cho *Growth Engine*).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8d69ebfd-fa9e-493c-8747-48c7f20d0840','17-referral-ecosystem','f3b19f9e-f90b-4340-bec8-753b32141fd1',3,'Chi tiết bóc tách 6 phần trong một Case Study chuẩn','chi-tiet-boc-tach-6-phan-trong-mot-case-study-chuan',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01dd7835-9a47-446c-95a0-1b5f75a43ae5','8d69ebfd-fa9e-493c-8747-48c7f20d0840',91,'image',NULL,'book/17-referral-ecosystem/6cef26db-00b1-4df9-8af9-96fdac6cdb2c-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a3f2c8ef-fef0-4c86-91ed-85faf0b98d4f','17-referral-ecosystem','8d69ebfd-fa9e-493c-8747-48c7f20d0840',4,'Định danh &amp; Chân dung bệnh nhân (Patient Profile)','inh-danh-amp-chan-dung-benh-nhan-patient-profile',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('530ffbbe-a834-459c-80ff-7347e700f246','a3f2c8ef-fef0-4c86-91ed-85faf0b98d4f',92,'text','Mở đầu bằng việc giới thiệu nhân vật chính một cách tự nhiên nhưng được bảo mật thông tin cá nhân theo quy chuẩn y tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c4b8177a-12f7-4d60-be16-230c8643c9f1','a3f2c8ef-fef0-4c86-91ed-85faf0b98d4f',93,'text','- **Thông tin cơ bản:** Tên viết tắt hoặc tên gọi ở nhà (Ví dụ: Chị V. Anh T.), tuổi, nghề nghiệp, địa phương sinh sống.- **Lý do đến khám chính (Chief Complaint):** Ghi nhận chính xác lời nói của bệnh nhân khi bước vào cửa (Ví dụ: *"Răng cửa bị thưa không dám cười"*, *"Mất 3 chiếc răng hàm không nhai được đồ cứng"*).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c78c0735-9742-4d82-95ec-a6020da71b31','17-referral-ecosystem','8d69ebfd-fa9e-493c-8747-48c7f20d0840',4,'Thực trạng lâm sàng &amp; Nỗi đau tâm lý (The Problem &amp; Pain Points)','thuc-trang-lam-sang-amp-noi-au-tam-ly-the-problem-amp-pain-points',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13e9bfa3-0200-41ea-a77e-a64a5ffbaa1e','c78c0735-9742-4d82-95ec-a6020da71b31',94,'text','Đây là phần tạo dựng bối cảnh. Bạn phải cho người đọc thấy mức độ nghiêm trọng của ca làm từ hai góc nhìn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b427211-3e60-45b2-98e7-0bd745cddbc7','c78c0735-9742-4d82-95ec-a6020da71b31',95,'text','- **Dữ liệu thô lâm sàng (Before Data):** Bật sẵn ảnh chụp trực diện nụ cười cũ, ảnh cận cảnh các góc răng lỗi, và ảnh chụp phim X-quang CT Cone Beam. Mô tả ngắn gọn bằng ngôn ngữ dễ hiểu kết hợp thuật ngữ y khoa nhẹ nhàng (Ví dụ: Tiêu xương răng vùng răng hàm, lệch lạc cung răng tầng mặt dưới).- **Nỗi đau tâm lý & Cuộc sống biến đổi:** Khai thác sâu vào việc tình trạng răng miệng đó đã tàn phá cuộc sống của họ thế nào. Họ đã phải từ bỏ những món ăn yêu thích ra sao? Họ đã tự ti, phải lấy tay che miệng khi giao tiếp với đối tác thế nào?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8831fb44-1a36-437e-a9ec-fcc7502db82d','17-referral-ecosystem','8d69ebfd-fa9e-493c-8747-48c7f20d0840',4,'Phác đồ điều trị &amp; Giải pháp công nghệ (The Solution)','phac-o-ieu-tri-amp-giai-phap-cong-nghe-the-solution',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49ae0713-359f-495c-b9f4-03ebf337bfad','8831fb44-1a36-437e-a9ec-fcc7502db82d',96,'text','Chứng minh năng lực của phòng khám bằng cách đưa ra câu trả lời cho bài toán khó phía trên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1473ba11-fdf2-49ef-960d-c84b9c699bdb','8831fb44-1a36-437e-a9ec-fcc7502db82d',97,'text','- **Giải pháp y khoa chọn lọc:** Giải thích lý do vì sao Bác sĩ lại chọn phương án này mà không chọn phương án khác (Ví dụ: Tại sao ca này phải cấy Implant chịu lực tức thì thay vì làm cầu răng sứ truyền thống).- **Bảo chứng công nghệ:** Nêu bật các công nghệ tiên tiến của phòng khám đã tham gia hỗ trợ ca làm (Máy quét dấu hàm 3D iTero, công nghệ cấy implant không đau Piezotome...) để định vị tính hiện đại của *Clinic System*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d0ef1af2-d33e-430c-9a42-2d5b9276d99c','17-referral-ecosystem','8d69ebfd-fa9e-493c-8747-48c7f20d0840',4,'Nhật ký tiến trình can thiệp (The Treatment Journey)','nhat-ky-tien-trinh-can-thiep-the-treatment-journey',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd4f1fd3-3c5d-4ab8-b6fc-02bf14d34582','d0ef1af2-d33e-430c-9a42-2d5b9276d99c',98,'text','Xóa bỏ hoàn toàn định kiến "làm răng là đau đớn, là kéo dài mệt mỏi" bằng cách tóm tắt lộ trình êm ái:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62be9a42-8b95-467c-aa08-63b29e347ed1','d0ef1af2-d33e-430c-9a42-2d5b9276d99c',99,'text','- **Các mốc thời gian cốt lõi:** Ca làm đi qua mấy giai đoạn? Mỗi giai đoạn mất bao lâu? (Ví dụ: Giai đoạn 1 nhổ răng khôn lành thương trong 7 ngày, giai đoạn 2 siết răng chỉnh nha chu kỳ 4 tuần/lần).- **Ghi chú cảm xúc trên ghế nha:** Cài cắm các chi tiết trải nghiệm thực tế để trấn an người xem (Ví dụ: *"Trong suốt 30 phút phẫu thuật, bệnh nhân hoàn toàn tỉnh táo, nghe nhạc thư giãn và không có cảm giác đau đớn nhờ kỹ thuật gây tê tầng"*).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0736ef89-0217-4471-a367-b4796a8ec7c4','17-referral-ecosystem','8d69ebfd-fa9e-493c-8747-48c7f20d0840',4,'Kết quả lột xác &amp; Nghiệm thu lâm sàng (The Outcome - After)','ket-qua-lot-xac-amp-nghiem-thu-lam-sang-the-outcome-after',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4715a517-3558-4acd-9070-48a2b9786738','0736ef89-0217-4471-a367-b4796a8ec7c4',100,'text','Khoảnh khắc tạo ra cú chạm thị giác mạnh nhất (Wow Peak). Phần này bắt buộc phải hiển thị bằng hình ảnh chất lượng cao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e79c12a7-e34c-46cc-85e6-8eae11f6e64c','0736ef89-0217-4471-a367-b4796a8ec7c4',101,'text','- **Hình ảnh tương phản trực quan:** Đặt bức ảnh nụ cười mới ngay cạnh nụ cười cũ (Before - After) dưới cùng một góc chụp và điều kiện ánh sáng studio. Sự thay đổi rõ rệt về form răng, cung cười và tổng thể khuôn mặt chính là bằng chứng đắt giá nhất.- **Chỉ số nghiệm thu y khoa:** Khẳng định ca làm thành công về mặt sức khỏe (Khớp cắn đạt tỷ lệ chuẩn, chức năng ăn nhai khôi phục 99%, các răng sứ tích hợp nướu hồng hào, không viêm nhiễm).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('29024f13-231b-4116-8e51-a42820ecd742','17-referral-ecosystem','8d69ebfd-fa9e-493c-8747-48c7f20d0840',4,'Bằng chứng xã hội đi kèm (Social Proof Alignment)','bang-chung-xa-hoi-i-kem-social-proof-alignment',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4bab460-dcc1-4af8-849d-b9d7adae054a','29024f13-231b-4116-8e51-a42820ecd742',102,'text','Đóng gói Case Asset bằng cách gắn link hoặc trích dẫn các tài sản niềm tin (Trust Assets) trực tiếp của chính nhân vật đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15b84d14-bc02-43fc-86c1-7d4e367f933e','29024f13-231b-4116-8e51-a42820ecd742',103,'text','- **Lời trích dẫn (Quote):** Lời cảm ơn hoặc chia sẻ mộc mạc của bệnh nhân sau khi nhìn thấy kết quả.- **Đường link chứng thực:** Đính kèm ảnh chụp màn hình bài review 5 sao mà khách hàng này đã viết trên Google Maps, hoặc link video Short Testimonial họ ngồi chia sẻ tại quầy lễ tân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca2e9218-a68e-419e-8f0f-c52bab6ab4e8','29024f13-231b-4116-8e51-a42820ecd742',104,'text','**Quy tắc biên tập nội dung số:** Khi chuyển hóa cấu trúc này thành các bài viết truyền thông trên Facebook hoặc kịch bản video ngắn trên TikTok, hãy tuân thủ nguyên lý: **Hạ thấp thuật ngữ hàn lâm - Đẩy cao câu chuyện con người.** Hãy biến một ca bệnh khô khan thành một câu chuyện truyền cảm hứng về hành trình tìm lại sự tự tin và hạnh phúc của một cuộc đời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73ab2d4f-0406-4054-bb3f-682882d693dc','29024f13-231b-4116-8e51-a42820ecd742',105,'text','**Lời khuyên thực chiến từ Dental Empire OS:** Hãy thiết lập một kỷ luật sắt cho đội ngũ trợ thủ lâm sàng: *Không có hình ảnh Before chuẩn quy định thì tuyệt đối không được cho Bác sĩ chạm tay vào điều trị.* Sự nghiêm túc trong khâu lưu trữ dữ liệu ở những ngày đầu tiên chính là thứ phân biệt một phòng khám cỏ với một hệ thống nha khoa vận hành đẳng cấp quốc tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aab21c02-08c0-44ad-b5c3-8e19d34872e5','17-referral-ecosystem',NULL,2,'17.10 Gợi ý chính sách Referral Offer','1710-goi-y-chinh-sach-referral-offer',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3fa3f771-53b6-43ca-bba3-673b00e2efff','aab21c02-08c0-44ad-b5c3-8e19d34872e5',106,'text','**Nghệ thuật tri ân tinh tế và lằn ranh đạo đức trong y khoa**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1120ba55-ebfb-4cb2-b6a0-93a5950c2169','aab21c02-08c0-44ad-b5c3-8e19d34872e5',107,'text','Trong kiến trúc vận hành của **Dental Empire OS**, chính sách ưu đãi giới thiệu (Referral Offer) là một trong những phần nhạy cảm nhất. Nếu làm không khéo, phòng khám RHM của bạn sẽ ngay lập tức bị thị trường gắn mác là "thương mại hóa", tạo cảm giác "mua bán bệnh nhân" hoặc biến những người bệnh nhân trung thành thành những cộng tác viên môi giới ăn chia hoa hồng thô thiển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('83500988-2f92-4a6d-b265-b978ae31ef37','aab21c02-08c0-44ad-b5c3-8e19d34872e5',108,'text','Y khoa là một ngành nghề đặc thù dựa trên đạo đức và lòng tin. Khi một bệnh nhân giới thiệu người thân đến với bạn, họ đang dùng uy tín cá nhân của mình để bảo chứng. Nếu bạn gửi cho họ một cục tiền mặt hay dùng những thuật ngữ như "chiết khấu %", "tiền môi giới", bạn đang vô tình hạ thấp giá trị hành động tử tế của họ, khiến họ cảm thấy tổn thương và mang tâm lý tội lỗi vì đã "kiếm tiền trên nỗi đau của bạn bè".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cac520e6-5c07-4167-ba28-64c7e5d7434c','aab21c02-08c0-44ad-b5c3-8e19d34872e5',109,'text','Để giải bài toán cân não này, tôi thiết lập một công thức độc quyền cho hệ thống Referral Offer, đảm bảo sự cân bằng tuyệt đối giữa bài toán kinh doanh và lằn ranh y đức:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('761bbfd3-a909-4431-84ac-ae56da7e9ff3','aab21c02-08c0-44ad-b5c3-8e19d34872e5',110,'image',NULL,'book/17-referral-ecosystem/9e1c071f-4da0-4689-a574-ce18dbc6dc94-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('18fd835d-3432-4143-9260-7be7e701c97c','17-referral-ecosystem','aab21c02-08c0-44ad-b5c3-8e19d34872e5',4,'Bóc tách ba thành phần của công thức Referral Offer chuẩn','boc-tach-ba-thanh-phan-cua-cong-thuc-referral-offer-chuan',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc1976df-82c1-4d44-a599-217a1d01df29','18fd835d-3432-4143-9260-7be7e701c97c',111,'text','- **Cảm ơn tinh tế:** Toàn bộ quy trình trao gửi quà tặng tri ân phải được thực hiện bằng một ngôn từ trang trọng, lịch sự. Tuyệt đối cấm sử dụng các từ ngữ mang tính thương mại như *"hoa hồng"*, *"tiết kiệm chi phí"*, *"chiết khấu bán hàng"*. Hãy thay bằng *"quà tặng tri ân"*, *"đặc quyền gia đình"*, *"sự trân trọng từ Bác sĩ"*.- **Lợi ích thật:** Món quà hoặc đặc quyền được trao đi phải có giá trị sử dụng cao, mang lại lợi ích hữu hình cho cuộc sống hoặc sức khỏe của người nhận, khiến họ cảm thấy công sức và lòng tin của mình được đền đáp xứng đáng.- **Không làm giảm giá trị chuyên môn:** Tuyệt đối không sử dụng chiêu trò giảm giá sâu (Discount) dịch vụ lâm sàng theo kiểu phá giá. Việc giảm giá vô tội vạ sẽ tự tay giết chết định vị chuyên gia tầng cao (**Authority Check**) của Bác sĩ, khiến khách hàng hoài nghi về chất lượng vật liệu hoặc tay nghề điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f7fbb579-1378-467d-8f19-e7b5a8e8b9ab','17-referral-ecosystem','aab21c02-08c0-44ad-b5c3-8e19d34872e5',4,'Các dạng định hình Referral Offer thực chiến và tinh tế','cac-dang-inh-hinh-referral-offer-thuc-chien-va-tinh-te',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba19eb0e-66e1-4043-b547-3807e95b4d04','f7fbb579-1378-467d-8f19-e7b5a8e8b9ab',112,'text','Thay vì trả tiền mặt, hệ thống chăm sóc của bạn hãy áp dụng 3 hình thức đóng gói ưu đãi tinh hoa dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7848fcc2-5a34-426c-902b-b96dd6220036','17-referral-ecosystem','f7fbb579-1378-467d-8f19-e7b5a8e8b9ab',5,'Định dạng 1: Cơ chế Tri ân Song phương (Dual-Sided Health Perks)','inh-dang-1-co-che-tri-an-song-phuong-dual-sided-health-perks',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d01ceb74-11c4-46be-9265-5f4661322580','7848fcc2-5a34-426c-902b-b96dd6220036',113,'text','Đây là hình thức cả người giới thiệu (Khách cũ) và người được giới thiệu (Khách mới) đều nhận được những đặc quyền tương xứng, tạo sự thoải mái cho cả hai bên khi tương tác:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af1e2027-edba-418d-8246-d23c20266ff3','7848fcc2-5a34-426c-902b-b96dd6220036',114,'text','- **Đối với khách mới:** Nhận được một suất "Tầm soát sức khỏe răng miệng toàn diện VIP" (bao gồm miễn phí chụp phim CT Cone Beam cắt lớp, scan mẫu hàm 3D và 1 buổi tư vấn chuyên sâu 1:1 cùng Bác sĩ trưởng ca) trị giá 1.500.000đ.- **Đối với khách cũ:** Hệ thống tự động gửi tặng một set quà chăm sóc răng miệng cao cấp (Máy tăm nước sóng siêu âm công nghệ mới hoặc Bàn chải điện cao cấp) gửi đến tận nhà kèm thư tay cảm ơn của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('538a715b-bca0-4917-8233-2e7c6be8e7e9','17-referral-ecosystem','f7fbb579-1378-467d-8f19-e7b5a8e8b9ab',5,'Định dạng 2: Nâng cấp Đặc quyền Gia đình (The Family Legacy Privilege)','inh-dang-2-nang-cap-ac-quyen-gia-inh-the-family-legacy-privilege',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eea21527-7a5a-4ef6-8d31-affe76acf99d','538a715b-bca0-4917-8233-2e7c6be8e7e9',115,'text','Biến hành động giới thiệu thành một công cụ tích lũy để gia tăng thứ hạng thành viên cho cả hộ gia đình:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa723dcc-c632-433b-bc19-fb98aea8dc0a','538a715b-bca0-4917-8233-2e7c6be8e7e9',116,'text','- Khi bệnh nhân cũ giới thiệu thành công 2 - 3 người thân đến điều trị ca lớn, toàn bộ gia đình của họ (vợ/chồng, con cái, bố mẹ) sẽ được nâng cấp thẳng lên hạng thẻ **Family VIP**.- **Đặc quyền đi kèm:** Miễn phí hoàn toàn dịch vụ cạo vôi răng, đánh bóng và kiểm tra răng định kỳ cho tất cả các thành viên trong gia đình trong vòng 3 - 5 năm. Đây là món quà đánh trúng tâm lý muốn bảo vệ tổ ấm của người Việt, gắn kết trọn đời cả gia đình khách hàng với thương hiệu của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1625004d-e96c-494d-8477-66a2a00fbe38','17-referral-ecosystem','f7fbb579-1378-467d-8f19-e7b5a8e8b9ab',5,'Định dạng 3: Quà tặng phong cách sống Phi Y Khoa (Lifestyle Luxury Perks)','inh-dang-3-qua-tang-phong-cach-song-phi-y-khoa-lifestyle-luxury-perks',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a9a3b7c-90fb-435e-bd53-3c2d772fba3c','1625004d-e96c-494d-8477-66a2a00fbe38',117,'text','Nếu bệnh nhân cũ là những người thuộc phân khúc cao cấp, có điều kiện tài chính tốt (khách làm răng sứ toàn hàm, Implant toàn hàm All-on-X), họ không cần tiền và cũng không quá bận tâm đến voucher giảm giá răng. Thứ họ cần là **sự công nhận và trải nghiệm đẳng cấp**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ea1ad33-cc43-44f0-8772-e692ee32e308','1625004d-e96c-494d-8477-66a2a00fbe38',118,'text','- Tặng một đêm nghỉ dưỡng tại resort 5 sao cao cấp hoặc một liệu trình Spa chăm sóc sức khỏe toàn thân tại các trung tâm trị liệu uy tín.- Món quà được gửi đi dưới danh nghĩa cá nhân của Bác sĩ trưởng phòng khám: *"Nhân dịp ca điều trị của người nhà anh/chị thành công tốt đẹp, Bác sĩ Vinh có một món quà nhỏ tri ân gu thẩm mỹ và sự tin tưởng của anh/chị dành cho đội ngũ"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('30706a15-7051-4708-afe2-b7129f862597','1625004d-e96c-494d-8477-66a2a00fbe38',119,'image',NULL,'book/17-referral-ecosystem/b3ffe74e-3dba-4714-a7c3-555bb606be36-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eb93d6cc-208e-454c-80c8-ee9ef61f5f30','17-referral-ecosystem','aab21c02-08c0-44ad-b5c3-8e19d34872e5',4,'Nghệ thuật trao quà và kịch bản kích hoạt xúc cảm','nghe-thuat-trao-qua-va-kich-ban-kich-hoat-xuc-cam',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8d3a1ba-4dbc-43fc-86cb-e73b63eae7c6','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',120,'text','Món quà quý không bằng cách trao. Để Referral Offer chạm đến tầng sâu nhất của lòng biết ơn, quy trình gửi quà phải tuân thủ nghiêm ngặt nguyên tắc: **Cá nhân hóa và Trân trọng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f84312b-6fc7-4395-ba04-3a9688daf28b','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',121,'text','**Quy chuẩn thực thi:** Món quà tri ân gửi đi bắt buộc phải đi kèm một **Tấm thiệp viết tay bằng mực mực xanh của chính Bác sĩ điều trị chính**, tuyệt đối không dùng thiệp in công nghiệp hàng loạt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6550255c-2365-4d64-b562-1c2bfac9a771','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',122,'text','Mẫu kịch bản tin nhắn Zalo gửi thông báo tri ân tinh tế:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86f818f6-fe32-416d-ab36-c362cfe9e40d','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',123,'text','"Chào anh/chị **[Tên_Khách_Cũ]**, em là **[Tên_Nhân_Viên]** thuộc bộ phận Quản trị trải nghiệm của Nha khoa **[Tên_Thương_Hiệu]** ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07120ade-d2a7-430b-9a85-2dce9a0ef579','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',124,'text','Thưa anh/chị, ca phẫu thuật điều trị răng cho anh/chị **[Tên_Khách_Mới]** (người nhà do đích thân anh/chị tin tưởng gửi gắm) ngày hôm nay đã hoàn thành thành công xuất sắc tốt đẹp ạ. Anh **[Tên_Khách_Mới]** hiện tại đã thoải mái và gửi lời cảm ơn phòng khám rất nhiều.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('064d9444-4366-4268-bf82-13e20ec75cc0','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',125,'text','Tập thể đội ngũ Y Bác sĩ bên em hiểu rằng, để trao đi một lời giới thiệu liên quan đến sức khỏe là anh/chị đã dành cho bên em một niềm tin vô cùng lớn lao. Để bày tỏ lòng tri ân sâu sắc vì sự đồng hành tử tế đó, Bác sĩ trưởng ca **[Tên_Bác_Sĩ]** có chuẩn bị một món quà đặc quyền là **[Tên_Món_Quà, ví dụ: Thẻ chăm sóc răng VIP Family trọn năm]** dành riêng cho anh/chị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d9c7ab7-dfd5-4d5e-a3eb-aa1421885d56','eb93d6cc-208e-454c-80c8-ee9ef61f5f30',126,'text','Phòng khám xin phép được gửi món quà này đến địa chỉ nhà riêng của mình tại **[Địa_Chỉ_Khách]** vào ngày mai nhé ạ. Một lần nữa, chúng em cảm ơn anh/chị rất nhiều vì đã giúp phòng khám lan tỏa những giá trị chăm sóc răng miệng khoa học đến với cộng đồng!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6e67fc17-3d7d-4338-b02a-0522c472c92a','17-referral-ecosystem',NULL,2,'17.11 Các nguồn referral chính - bản đồ khai thác dòng khách truyền miệng đa tầng','1711-cac-nguon-referral-chinh-ban-o-khai-thac-dong-khach-truyen-mieng-a-tang',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1c657068-b6c8-4d35-af14-b1f39fffe765','6e67fc17-3d7d-4338-b02a-0522c472c92a',127,'text','Để hệ sinh thái lan tỏa vận hành với công suất tối đa, nhà quản trị không được phép nhìn nhận nguồn giới thiệu một cách chung chung. Trong cấu trúc của **Dental Empire OS**, dòng khách Referral được chia thành 5 nguồn mạch huyết mạch độc lập. Việc phân rã này giúp phòng khám RHM của bạn thiết kế được các kịch bản tiếp cận chuẩn xác và không bỏ sót bất kỳ tài nguyên nào trên thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5b81089f-30e1-4949-96ee-e4172988590d','17-referral-ecosystem','6e67fc17-3d7d-4338-b02a-0522c472c92a',3,'Nguồn 1: Patient-to-Patient (Tệp bệnh nhân cũ)','nguon-1-patient-to-patient-tep-benh-nhan-cu',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7df06b7a-6a7c-4ee7-9169-86d0436fdd37','5b81089f-30e1-4949-96ee-e4172988590d',128,'text','***Trục xương sống của hệ thống***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f683101e-5a25-4383-8834-cabacea1c4bf','5b81089f-30e1-4949-96ee-e4172988590d',129,'text','Đây là nguồn giới thiệu phổ biến nhất, chiếm từ 60% - 70% tổng lượng khách truyền miệng của phòng khám. Nguồn này được chia thành hai nhóm nhỏ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64ac312b-d139-48c7-b750-4952b513ddc0','5b81089f-30e1-4949-96ee-e4172988590d',130,'text','- **Vòng tròn ruột thịt (Gia đình, họ hàng):** Khách hàng sau khi làm răng thấy ăn nhai tốt, không đau sẽ lập tức dắt bố mẹ đến cấy implant, đưa con cái đến niềng răng hoặc đưa vợ/chồng đến thẩm mỹ. Nhóm này có tỷ lệ chốt phác đồ gần như 100% vì mức độ tin tưởng tuyệt đối.- **Vòng tròn xã hội (Bạn bè, đồng nghiệp, hàng xóm):** Kích hoạt mạnh nhất sau các ca "lột xác" về thẩm mỹ. Khi diện mạo của bệnh nhân thay đổi, nụ cười rạng rỡ hơn, những người xung quanh sẽ chủ động hỏi thăm.- *Cách tối ưu:* Áp dụng chính sách **Nâng cấp Đặc quyền Gia đình (Family VIP)** và trao tặng các thẻ tầm soát răng miệng miễn phí để họ mang đi tặng bạn bè vào các mốc cảm xúc đỉnh cao (Wow Peak).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e18f8d80-e48d-4aca-b176-41b4d05b2816','17-referral-ecosystem','6e67fc17-3d7d-4338-b02a-0522c472c92a',3,'Nguồn 2: Doctor-to-Doctor (Đối tác chuyên môn)','nguon-2-doctor-to-doctor-oi-tac-chuyen-mon',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f05e3c2-fb0f-40d5-b2fa-3c715713e44c','e18f8d80-e48d-4aca-b176-41b4d05b2816',131,'text','***Lời bảo chứng từ giới học thuật***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8397b1b1-3cf3-4d91-93b1-2beda69f2c6b','e18f8d80-e48d-4aca-b176-41b4d05b2816',132,'text','Đây là nguồn referral có giá trị chuyển đổi cực kỳ cao nhưng lại thường bị các chủ nha khoa bỏ quên. Bệnh nhân có xu hướng tin tưởng 100% vào lời khuyên của một chuyên gia y tế khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('87b01529-289b-48f6-97d4-f4a0474ffd5f','e18f8d80-e48d-4aca-b176-41b4d05b2816',133,'text','- **Bác sĩ đa khoa, bác sĩ Tai-Mũi-Họng, Nhi khoa:** Những người tiếp xúc với bệnh nhân gặp các vấn đề liên đới (ví dụ: viêm xoang do biến chứng răng, lệch khớp thái dương hàm gây đau nửa đầu, trẻ bị thở miệng dẫn đến lệch lạc răng).- **Nha sĩ tuyến dưới hoặc phòng khám nhỏ:** Những cơ sở không đủ máy móc hoặc không có giấy phép thực hiện các ca phẫu thuật phức tạp (như cấy Implant toàn hàm, nhổ răng khôn mọc ngầm sát dây thần kinh, chỉnh nha tăng trưởng). Họ sẽ giới thiệu ca khó lên phòng khám của bạn để đảm bảo an toàn cho bệnh nhân.- *Cách tối ưu:* Xây dựng mối quan hệ cá nhân với các đồng nghiệp y khoa, cam kết bàn giao lại bệnh nhân sau khi điều trị xong phân hệ khó và có chính sách tri ân chuyên môn tinh tế dưới dạng tài trợ học bổng, hội thảo khoa học.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f27c6c18-aeb7-4226-bf01-e0ff9f72faa7','17-referral-ecosystem','6e67fc17-3d7d-4338-b02a-0522c472c92a',3,'Nguồn 3: Internal Staff Referral (Nhân sự nội bộ)','nguon-3-internal-staff-referral-nhan-su-noi-bo',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8bb7ae29-03ee-4139-87a5-5eaf14566808','f27c6c18-aeb7-4226-bf01-e0ff9f72faa7',134,'text','***Thước đo văn hóa doanh nghiệp***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8381070f-6f35-4af6-82f8-c57e0735041c','f27c6c18-aeb7-4226-bf01-e0ff9f72faa7',135,'text','Một phòng khám có chất lượng thực sự tử tế hay không, hãy nhìn vào việc nhân viên có dám đưa người nhà của họ đến điều trị hay không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dac1e5f8-8a91-49d1-8e77-5a7542a28465','f27c6c18-aeb7-4226-bf01-e0ff9f72faa7',136,'text','- **Đối tượng:** Từ Bác sĩ, Trợ thủ, Lễ tân cho đến chú Bảo vệ, cô Tạp vụ. Họ là những người chứng kiến toàn bộ quy trình vô trùng, tay nghề thật của bác sĩ và chất lượng vật liệu phía sau hậu trường. Khi chính họ tự hào giới thiệu người thân đến làm, đó là lời quảng cáo quyền lực nhất đối với khách hàng vãng lai.- *Cách tối ưu:* Thiết kế chính sách phúc lợi chăm sóc răng miệng đặc quyền cho bản thân nhân sự và giảm giá sâu (chỉ thu giá gốc vật liệu) dành riêng cho tứ thân phụ mẫu của nhân viên. Gắn KPI hoặc thưởng nóng cho những nhân sự tích cực lan tỏa thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('291672e8-2e85-45a5-9e95-992c54aa34bd','17-referral-ecosystem','6e67fc17-3d7d-4338-b02a-0522c472c92a',3,'Nguồn 4: Local Cross-Referral (Đối tác liên ngành địa phương)','nguon-4-local-cross-referral-oi-tac-lien-nganh-ia-phuong',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3a83a66-5bd3-4f94-9a62-461261bb3c93','291672e8-2e85-45a5-9e95-992c54aa34bd',137,'text','*Chiếm lĩnh thị trường khu vực*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('860280be-6ea8-4237-9b23-f6e90233d3dd','291672e8-2e85-45a5-9e95-992c54aa34bd',138,'text','Nha khoa bản chất vẫn là một mô hình kinh doanh mang tính bán kính (Location-based). Khách hàng ưu tiên lựa chọn những phòng khám thuận tiện cho việc đi lại. Do đó, việc liên minh với các doanh nghiệp địa phương xung quanh là chiến lược thông minh để quét sạch tệp khách khu vực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09b968a1-eda2-4ccb-a1c0-1b4a8e35a4ff','291672e8-2e85-45a5-9e95-992c54aa34bd',139,'text','- **Đối tượng liên minh:** Các trung tâm Spa, Thẩm mỹ viện, Salon tóc cao cấp, Phòng gym, hoặc các trường mầm non/tiểu học chất lượng cao nằm trong bán kính 3 - 5km xung quanh phòng khám. Đây là những nơi nắm giữ tệp khách hàng có cùng chân dung và khả năng chi trả với nha khoa của bạn.- *Cách tối ưu:* Đặt các standee tinh tế hoặc gửi các voucher đặc quyền chăm sóc răng miệng VIP của nha khoa tại quầy thanh toán của đối tác, ngược lại, nha khoa cũng hỗ trợ truyền thông cho dịch vụ của họ tại sảnh chờ của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('24cae1af-485e-4a03-a9e3-fbbe00a04a24','17-referral-ecosystem','6e67fc17-3d7d-4338-b02a-0522c472c92a',3,'Nguồn 5: Community &amp; Micro-Influencers (Đại sứ cộng đồng)','nguon-5-community-amp-micro-influencers-ai-su-cong-ong',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f8577e8-e23e-4347-a311-13eb268412ba','24cae1af-485e-4a03-a9e3-fbbe00a04a24',140,'text','***Tiếng nói của những người có gu***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70c095d8-f383-45ca-a4ec-91da50dbfccb','24cae1af-485e-4a03-a9e3-fbbe00a04a24',141,'text','Không cần phải bỏ ra hàng trăm triệu để thuê các ngôi sao hạng A, hệ thống Referral tập trung vào các "KOLs bán kính" - những người có tầm ảnh hưởng lớn trong một cộng đồng nhỏ xung quanh phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3abb9e03-a4f4-4462-8b61-3d75d50b13be','24cae1af-485e-4a03-a9e3-fbbe00a04a24',142,'text','- **Đối tượng:** Trưởng hội cư dân của các tòa chung cư cao cấp bên cạnh phòng khám, admin của các hội nhóm "Mẹ bỉm sữa" tại địa phương, hoặc các KOCs (Key Opinion Consumers) sở hữu vài ngàn lượt theo dõi thực tế trên TikTok/Facebook tại khu vực.- *Cách tối ưu:* Mời họ đến trải nghiệm dịch vụ cạo vôi răng hoặc tẩy trắng răng miễn phí với quy trình trải nghiệm 5 sao. Khi họ thực sự bị thuyết phục bởi hệ thống vận hành của bạn, họ sẽ tự động chia sẻ lên group cư dân hoặc trang cá nhân một cách tự nhiên nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('83beb8a8-2e0a-403c-b9b9-d689c37850dd','17-referral-ecosystem',NULL,2,'17.12 CRM for Referral Ecosystem','1712-crm-for-referral-ecosystem',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ffd33c57-32e9-409b-b3c9-bf151dbbc481','83beb8a8-2e0a-403c-b9b9-d689c37850dd',143,'text','**Số hóa dữ liệu lan tỏa và kiến trúc các trường dữ liệu bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6b232945-ac3f-4b31-af28-2464acde239e','83beb8a8-2e0a-403c-b9b9-d689c37850dd',144,'text','Trong kiến trúc vận hành của **Dental Empire OS**, tôi luôn nhấn mạnh một nguyên lý: **"Cái gì không đo lường được thì không thể quản trị được, cái gì không số hóa được thì không thể tự động hóa."**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb96e688-92c6-44df-810f-a5c47ab9ff4f','83beb8a8-2e0a-403c-b9b9-d689c37850dd',145,'text','Hệ sinh thái Referral sẽ nhanh chóng sụp đổ nếu bạn quản trị nó bằng sổ tay, bằng trí nhớ của lễ tân hoặc những ghi chú rời rạc. Nhân viên sẽ quên gửi quà tri ân cho khách cũ, lễ tân sẽ quên gắn nguồn khi khách mới đến, và bạn với tư cách là chủ phòng khám sẽ hoàn toàn mù mờ về chỉ số ROI (Tỷ suất hoàn vốn) của nguồn khách này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af2fb1e7-e804-4d4b-86cb-0bb59fc6b3da','83beb8a8-2e0a-403c-b9b9-d689c37850dd',146,'text','Để biến Referral thành một cỗ máy tự chạy mượt mà, hệ thống CRM của phòng khám RHM bắt buộc phải được thiết lập các trường dữ liệu (Data Fields) có cấu trúc, giúp liên kết chặt chẽ giữa Hồ sơ người giới thiệu (Referrer) và Hồ sơ người được giới thiệu (Referee).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('722b6810-c7c6-4cb9-a3c0-cd56e901aa64','17-referral-ecosystem','83beb8a8-2e0a-403c-b9b9-d689c37850dd',3,'Các trường dữ liệu cốt lõi cần thiết lập trên CRM','cac-truong-du-lieu-cot-loi-can-thiet-lap-tren-crm',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c0e39e50-a8a0-4892-9fbf-4f2899f16a69','722b6810-c7c6-4cb9-a3c0-cd56e901aa64',147,'text','Dưới đây là sơ đồ các trường dữ liệu bắt buộc phải cấu hình trong hệ thống CRM nha khoa của bạn, chia thành 3 phân nhóm chức năng để tối ưu hóa khả năng quét và trích xuất báo cáo:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('599ef360-0480-4f20-9066-d3e7a256ec5c','17-referral-ecosystem','722b6810-c7c6-4cb9-a3c0-cd56e901aa64',5,'1.1 Nhóm trường dữ liệu tại Hồ sơ Khách hàng mới (Người được giới thiệu)','11-nhom-truong-du-lieu-tai-ho-so-khach-hang-moi-nguoi-uoc-gioi-thieu',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf5dc5d0-e7cc-4ad6-bd69-65033b3ae680','599ef360-0480-4f20-9066-d3e7a256ec5c',148,'text','Khi tiếp nhận một lead từ nguồn referral, bộ phận Sales/Lễ tân phải điền đầy đủ các trường sau để không làm đứt gãy phả hệ dữ liệu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98e11889-88cd-46c7-83f1-33c8995276a4','599ef360-0480-4f20-9066-d3e7a256ec5c',149,'text','- **Nguồn khách hàng (Lead Source):** Gắn thẻ cố định là `Referral` (để phân biệt với Facebook Ads, TikTok Org, Google Maps, Khách vãng lai).- **Mã người giới thiệu (Referrer ID):** Nhập ID hoặc Số điện thoại của khách hàng cũ đã giới thiệu ca này. Trường này sẽ tự động link (liên kết) hồ sơ của 2 người với nhau.- **Mối quan hệ (Referral Relationship):** Trường drop-down chọn các giá trị: *Bố mẹ / Vợ chồng / Con cái / Bạn bè / Đồng nghiệp / Đối tác liên ngành.*- **Trạng thái chuyển hóa (Referral Lead Stage):** Theo dõi tiến độ của người mới: *Mới tiếp nhận **\\rightarrow** Đã đặt lịch khám **\\rightarrow** Đã đến khám **\\rightarrow** Đang điều trị **\\rightarrow** Đã hoàn thành.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('36d6790a-7130-409f-bb83-b61e46b517b3','17-referral-ecosystem','722b6810-c7c6-4cb9-a3c0-cd56e901aa64',5,'1.2 Nhóm trường dữ liệu tại Hồ sơ Khách hàng cũ (Người đi giới thiệu)','12-nhom-truong-du-lieu-tai-ho-so-khach-hang-cu-nguoi-i-gioi-thieu',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('685cc224-6c82-45cf-aa04-27888530c5a2','36d6790a-7130-409f-bb83-b61e46b517b3',150,'text','Hệ thống CRM sẽ tự động tích lũy dữ liệu vào hồ sơ của người giới thiệu dựa trên hành vi của những người mới mà họ dẫn đến:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a036bb39-965f-45b8-b785-98748943e3ef','36d6790a-7130-409f-bb83-b61e46b517b3',151,'text','- **Số lượng giới thiệu thành công (Total Referrals):** Tổng số lượng người mới đã đến khám/điều trị thực tế từ nguồn của khách hàng này.- **Tổng doanh thu lan tỏa (Total Referral Revenue):** Tổng số tiền mà những người được giới thiệu đã thanh toán cho phòng khám. Đây là chỉ số tối quan trọng để định vị khách VIP VIP.- **Hạng thành viên giới thiệu (Referral Tier):** Tự động nhảy hạng dựa trên số lượng ca giới thiệu (Ví dụ: *Silver Ambassador (1-2 ca) **\\rightarrow** Gold Ambassador (3-5 ca) **\\rightarrow** Diamond Ambassador (>5 ca)*).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91254681-48c9-4af0-9b3a-e1862a3fae61','17-referral-ecosystem','722b6810-c7c6-4cb9-a3c0-cd56e901aa64',5,'1.3 Nhóm trường Quản trị Phần thưởng &amp; Tương tác hậu trường (Reward Log)','13-nhom-truong-quan-tri-phan-thuong-amp-tuong-tac-hau-truong-reward-log',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('855a702a-6fa7-488d-b740-87ad15516d0f','91254681-48c9-4af0-9b3a-e1862a3fae61',152,'text','Trường dữ liệu này giúp bộ phận CSKH không bao giờ quên nghĩa vụ tri ân, đảm bảo tính thực thi tuyệt đối của chính sách *Referral Offer*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e088d8a6-ceb7-443f-8af1-e67ebbb1b294','17-referral-ecosystem','83beb8a8-2e0a-403c-b9b9-d689c37850dd',3,'Kích hoạt Trigger tự động hóa (Automation) dựa trên trường dữ liệu','kich-hoat-trigger-tu-ong-hoa-automation-dua-tren-truong-du-lieu',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1c7563f2-11e4-4f65-86c3-13abf0dbe171','e088d8a6-ceb7-443f-8af1-e67ebbb1b294',153,'text','Khi các trường dữ liệu trên được chuẩn hóa, hệ thống CRM sẽ tự động kích hoạt (Trigger) các kịch bản vận hành mà con người không cần can thiệp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b653d19e-9616-4735-a1ce-4279bcd32728','e088d8a6-ceb7-443f-8af1-e67ebbb1b294',154,'text','**Trigger 1:** Khi Trạng thái chuyển hóa của Khách hàng mới chuyển sang `Đã thanh toán phác đồ` \\rightarrow Hệ thống tự động tạo một nhiệm vụ (Task) cho bộ phận CSKH: *"Chuẩn bị quà tri ân gửi cho Khách hàng cũ [Tên_Người_Giới_Thiệu] và đưa thiệp cho Bác sĩ [Tên_Bác_Sĩ] ký tên"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('27c1da55-3287-440b-ac9c-fbd7de6477fa','e088d8a6-ceb7-443f-8af1-e67ebbb1b294',155,'text','**Trigger 2:** Khi Tổng doanh thu lan tỏa đạt mốc 100 triệu đồng \\rightarrow Hệ thống tự động chuyển đổi tag khách hàng cũ thành `Diamond_Ambassador`, đồng thời bắn một tin nhắn chúc mừng đặc quyền kèm mã số VIP cá nhân hóa qua Zalo OA.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb875004-314f-47ec-a6f0-45f600e87006','e088d8a6-ceb7-443f-8af1-e67ebbb1b294',156,'text','Thiết lập cấu trúc trường dữ liệu này trên CRM chính là bước cuối cùng để đóng gói toàn bộ chương **Growth Engine & Patient Experience** của bạn thành một thực thể công nghệ có thể tự vận hành và nhân chuỗi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc563a5f-c4ca-402e-9214-24f2be254483','17-referral-ecosystem',NULL,2,'17.13 Kết luận','1713-ket-luan',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44498983-8bc8-4c9c-bec9-520739c8a01d','dc563a5f-c4ca-402e-9214-24f2be254483',157,'text','**Referral Ecosystem là đỉnh cao của nghệ thuật quản trị nha khoa hữu cơ**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c774600a-ccc2-4842-8b4b-37d0a5a8f7be','dc563a5f-c4ca-402e-9214-24f2be254483',158,'text','Chúng ta khép lại cấu phần về **Referral Ecosystem (Hệ sinh thái giới thiệu)** với một nhận thức mang tính bản lề: Đây không phải là một chiến dịch tiếp thị ngắn hạn, mà là cái đích đến tối cao của một phòng khám RHM vận hành tử tế. Hệ sinh thái này sở hữu năng lực kỳ diệu trong việc chuyển hóa những nụ cười hạnh phúc, những lời cảm ơn vô hình của bệnh nhân thành một loại **Tài sản tăng trưởng dài hạn** có thể sờ nắn và đo lường được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a01023b8-5e6e-4753-b259-a3d3db72f81b','dc563a5f-c4ca-402e-9214-24f2be254483',159,'image',NULL,'book/17-referral-ecosystem/d4f8d2f3-137d-4c74-bd42-8fdc2c2a8fba-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39b5cc45-6365-4367-80c6-6e57e4b8805d','dc563a5f-c4ca-402e-9214-24f2be254483',160,'text','Khi dòng chảy Referral được khơi thông và vận hành tự động trên nền tảng công nghệ, phòng khám của bạn sẽ chính thức thoát khỏi sự lệ thuộc vào các thuật toán quảng cáo trả phí. Từ đây, doanh nghiệp không chỉ có thêm những khách hàng mới chất lượng cao, mà còn tự động sản sinh ra một hệ giá trị thực:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07c030ad-d831-4d7c-86bb-0a9de8bd3ca3','dc563a5f-c4ca-402e-9214-24f2be254483',161,'text','- **Niềm tin thật:** Thứ niềm tin không thể mua được bằng tiền quảng cáo, được chuyển giao trọn vẹn từ người thân sang người thân.- **Review thật:** Những dòng chia sẻ đầy cảm xúc, chứa từ khóa bệnh lý tự nhiên, tạo bệ phóng vững chắc cho tầng *Search Visibility* trên Google Maps.- **Case thật:** Kho tàng bằng chứng lâm sàng sống động, người thật việc thật, đập tan mọi pháo đài hoài nghi của những lead lạnh ngoài thị trường.- **Cộng đồng thật:** Bộ tộc của những bệnh nhân trung thành, yêu mến và sẵn sàng đứng ra bảo vệ, lan tỏa thương hiệu cho phòng khám.- **Doanh thu bền vững:** Biên lợi nhuận thuần tăng vọt nhờ chi phí thu mua khách hàng (CAC) tiệm cận bằng 0, tạo dòng tiền ổn định cho doanh nghiệp.- **Thương hiệu mạnh hơn:** Định vị nha khoa của bạn như một biểu tượng của sự uy tín, đẳng cấp và tử tế trong tâm trí khách hàng khu vực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a44ed9e-32b2-46b3-b4f7-000ce3ea4f37','dc563a5f-c4ca-402e-9214-24f2be254483',162,'text','**Mantra tối thượng của Dental Empire OS:** Quảng cáo giúp bạn có những khách hàng đầu tiên, nhưng chỉ có sự tử tế trong trải nghiệm và một hệ sinh thái Referral bài bản mới giúp bạn có cả một gia tộc khách hàng đi cùng phòng khám qua nhiều thế hệ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ae7961c-d1cb-44c5-87d4-eec360d4dbf1','dc563a5f-c4ca-402e-9214-24f2be254483',163,'text','Trong kiến trúc tổng thể của **Dental Empire OS**, Hệ sinh thái Referral không thể đứng độc lập. Nó không phải là một chiếc đũa thần có thể cứu vãn một phòng khám có chất lượng chuyên môn kém hay dịch vụ tồi tệ. Trái lại, Referral chính là **Tầng quả ngọt tăng trưởng tự nhiên** - là phần thưởng tất yếu chỉ xuất hiện sau khi phòng khám của bạn đã làm tốt và đồng bộ hóa các tầng nền móng vững chắc phía dưới:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cfc4ddf3-7ab9-4601-87c8-73a2e604784e','dc563a5f-c4ca-402e-9214-24f2be254483',164,'image',NULL,'book/17-referral-ecosystem/0db85b6a-d7f9-4db6-837b-16a6d29508ef-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc77c999-e2cf-4228-b1bc-04ac4e1c2f87','dc563a5f-c4ca-402e-9214-24f2be254483',165,'text','Khi bạn thiết lập được một trục dọc mượt mượt mà từ khâu làm nội dung sạch (**Content**), xây dựng uy tín chuyên gia (**Trust**), tối ưu tỷ lệ chốt phác đồ (**Conversion**), thực thi trải nghiệm ghế nha xuất sắc (**Patient Experience**), bám đuổi hậu phẫu chu đáo (**CSKH**) cho đến việc ghim chặt khách hàng vào bộ tộc của bạn (**Community**) - thì lúc đó, **Hệ sinh thái Referral** sẽ tự động kích hoạt như một động cơ vĩnh cửu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdfab62f-8541-47db-827a-4da810674dc9','dc563a5f-c4ca-402e-9214-24f2be254483',166,'text','Nó sẽ chạy liên tục, đều đặn, đưa phòng khám RHM của bạn bước vào kỷ nguyên tăng trưởng bùng nổ, tử tế, an toàn và không thể bị đánh bại trên thị trường nha khoa thực chiến.',NULL,NULL,NULL,NULL,NULL);
